-- Drop all existing policies on student_profiles to start fresh\nDROP POLICY IF EXISTS "Users can view own profile" ON public.student_profiles;\nDROP POLICY IF EXISTS "Users can update own profile" ON public.student_profiles;\nDROP POLICY IF EXISTS "Users can insert own profile" ON public.student_profiles;\nDROP POLICY IF EXISTS "Enable read for users based on user_id" ON public.student_profiles;\nDROP POLICY IF EXISTS "Enable insert for users based on user_id" ON public.student_profiles;\nDROP POLICY IF EXISTS "Enable update for users based on user_id" ON public.student_profiles;\nDROP POLICY IF EXISTS "student_profiles_select_own" ON public.student_profiles;\nDROP POLICY IF EXISTS "student_profiles_insert_own" ON public.student_profiles;\nDROP POLICY IF EXISTS "student_profiles_update_own" ON public.student_profiles;\nDROP POLICY IF EXISTS "student_profiles_all_own" ON public.student_profiles;\nDROP POLICY IF EXISTS "Allow users to manage their own profile" ON public.student_profiles;\nDROP POLICY IF EXISTS "profiles_own_access" ON public.student_profiles;\n\n-- Make sure RLS is enabled\nALTER TABLE public.student_profiles ENABLE ROW LEVEL SECURITY;\n\n-- Create clean, simple RLS policies\nCREATE POLICY "sp_select_own" ON public.student_profiles\n  FOR SELECT USING (auth.uid() = id);\n\nCREATE POLICY "sp_insert_own" ON public.student_profiles\n  FOR INSERT WITH CHECK (auth.uid() = id);\n\nCREATE POLICY "sp_update_own" ON public.student_profiles\n  FOR UPDATE USING (auth.uid() = id);\n\n-- Also ensure trial_requests table has correct policies\nALTER TABLE public.trial_requests ENABLE ROW LEVEL SECURITY;\n\nDROP POLICY IF EXISTS "Anyone can insert trial requests" ON public.trial_requests;\nDROP POLICY IF EXISTS "Users can view own requests" ON public.trial_requests;\n\nCREATE POLICY "tr_insert_any" ON public.trial_requests\n  FOR INSERT WITH CHECK (true);\n\nCREATE POLICY "tr_select_own" ON public.trial_requests\n  FOR SELECT USING (auth.uid() = student_id OR student_id IS NULL);